INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7277044','Він іде по воді','Музика: Марія Бурмака Слова: Марія Бурмака. Виконує: Марія Бурмака','uk','ukraine_1991',NULL,NULL,'youtube',NULL,'Він іде по воді, він тамує вогонь,
Не лишає слідів, окрім серця мого.
У тумані тіней одинока лиш тінь
Розбиватиме простір невидимих стін...

По воді, по воді і по краю небес,
Є надія одна, що тримає тебе
І тремтить між зірок полохлива свіча,
І за подихом терпне одне: "Ще не час..."

Ти боїшся тепла, ти тамуєш любов,
Ти мовчиш, бо слова забуваються знов,
І боїшся, що він може знов не прийти,
Тільки думка одна: Він іде по воді...

У секунди, що ти відраховуєш сам,
Тільки небо і небо вертає назад,
У пронизливій тиші він губить сліди
Мого подиху, тихше Він іде по воді...','[''pisni.org.ua'', ''cat:euromaydan'', ''Пісні Євромайдану'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7277044'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7277044','Він іде по воді','Він іде по воді, він тамує вогонь,
Не лишає слідів, окрім серця мого.
У тумані тіней одинока лиш тінь
Розбиватиме простір невидимих стін...

По воді, по воді і по краю небес,
Є надія одна, що тримає тебе
І тремтить між зірок полохлива свіча,
І за подихом терпне одне: "Ще не час..."

Ти боїшся тепла, ти тамуєш любов,
Ти мовчиш, бо слова забуваються знов,
І боїшся, що він може знов не прийти,
Тільки думка одна: Він іде по воді...

У секунди, що ти відраховуєш сам,
Тільки небо і небо вертає назад,
У пронизливій тиші він губить сліди
Мого подиху, тихше Він іде по воді...');
