INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_730147','Ой в Чистім Полі на Оболоні','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Щедрий вечір. Українські народні пісні. Упор. та передм. Н.Д.Якименко. - К.: Музична Україна, 1989. - 192 с.','Колядка стародавня: Українське Різдво Світа. В Чистому Полі Сам Плужок ходить. Загадав Приймак Плужком орати. Та наставляв Женців Хлопців-Молодців. Самогуртування: статеві, вікові та станові гурти. В Колядках і Щедрівках є образці статевих гуртів молоді та вікових відділів молоді і старших людей. Є там спомини про вандрівні й осілі гурти Хлопців-Молодців (вандрувати = бродити, блукати) - Й а в Лісі в Лісі й а в Медоборі; гурти для реліґійної пропаганди (типові гурти пізніших Колядників); вандрівні гурти для полагодження економічних справ (гурти "Купців"); гурти спеціальних ремісників, працюючих удома для родини; гурти фахових рільних робітників обох полів, працюючих окремо - Ой в Чистім Полі на Оболоні, гурти працівників старших; гурти мужви зі схильністю емансипувати себе від жіноцтва задля ідейних цілей — і такі ж гурти задля емансипації чисто статевої (безперечно пізніші, в округах, де вибивалася на верх матеровлада); гурти боєві і козацькі. Всі оті гурти уложилися в пам''яті народу неначе ступінь за ступенем в міру культурно-історичногої еволюції — і приявляються нам сьогодня у відповідній культурно-історичній характеристиці. Таке самогуртування народу в статеві, станові та вікові гурти лежало безперечно в засадах Старовіцького суспільного світогляду Українського народу, а не було ділом припадку. А що воно перейшло було в суспільну норму, свідчать про це Колядки й Щедрівки, які згадують часто про установу Трьох Сел на Україні і дають докази, що були вони не тільки в Старинні часи, але перетривали до новішої доби. Були це окремі села: Старих людей, Молодців (Парубків) і Дівчат. (Самогуртування: У праці Кс. Сосенка вжито "гуртуванняся", що відповідало б "самоорганізації" в сучасній науковій термінології. Самоорганізація як явище є предметом вивчення окремої сучасної науки — синергетики. Доречно говорити про етнологічну синергетику.) Є таких Колядок і Щедрівок про Три Села більше, та з образцями не однакової культурної доби, що якраз свідчить про колишню довготривалість тої суспільної установи. Схильність до народних чи племінних зборів. Оця дуже цікава Староукраїнська суспільна проблема варта всестороннього опрацювання; відкладемо її до ширшого розглянення при розділі про Щедрівки, бо найбільше на цю тему є Щедрівок; а тут рад би я дати вибрані приклади з Колядок і Щедрівок, щоби удовіднити, що тенденція народних чи племінних зборів, а вслід за тим і свято всенародного Збору на Україні, — яке треба розширити, окрім збору Різдвяного й Богоявлінського, і на Великодній, — має в основі дуже поважні етно-культурні задатки — і від них зачинаючи, треба би ці Свята поясняти. Бо — і зараз Українські всенародні святочні (церковні) збори, приміром Різдвяні, Йорданські й ін., мають давнє етно-суспільне забарвлення: загального збору поодиноких статевих гуртів і вікових відділів віку. Хто не довіряє, нехай придивиться до збору народу в великі свята по всіх церквах на Україні: нарід стоїть там самочинно поділений: по правій руці — на переді діти-хлопчики, за ними підростки, відтак старші господарі, за ними молодші господарі, а далі гурт парубоцтва; по лівій руці — на переді дівчатка-недолітки, за ними дівоцтво, за дівоцтвом бабусі (звичайно біля лавок), а в "бабинці" матусі та молодиці з маленькими діточками на руках. Такий Старовіцький лад є без виїмку по всій Україні, і нема цього у ніяких інших, т. зв. Індоєвропейських, народів, що окружають Українців. Щось подібного знаходимо у Жидів в їх Святинях, де чоловіки в часі богослужень займають долішню наву Святині, а жіноцтво перебуває на горішніх її поверхах. Гуртовий статевий поділ є і в Турецько-Арабських Святинях. Праісторичність і містика самогуртування. Майже всі Колядки і Щедрівки на тему вікових і статевих гуртів відзначуються Місячно-мітольоґічною символікою, що є характеристикою старинности тих Пісень тай цієї теми. Через оцю мітольоґічну закраску набирає і сама тема мітичного значення, що однакож не відбирає їй значення реальної традиції, а за те окружує її німбом Святости і творить з неї окремий об''єкт шанування й скріплює її повагу. Але все те вказує, що традиції ці не історичні, але праісторичні. Це стверджую, супроти того, що дехто з Українських істориків видить у Колядках про більші молодецькі гурти ("700 молодців") — спомини історичних військових орґанізацій, буцім-то зорґанізованих військових полків, готових до найму. Забарвлення цих Колядок є може пізніше, але воно не затирає в них Старинних традицій. Статеві гурти для рільних робіт: пракультурні образці. Дуже багато Колядок співає про статеві гурти Молодців і Дівчат, окремо з''орґанізованих для рільних робіт. Звертають увагу Колядки, де співається про гурти самих Хлопців; так неначе б був час, коли Дівчат держано безоглядно вдома, або ізольованими гуртами, не пускаючи їх навіть на конечні господарські роботи. Та наставляв Женців Хлопців-Молодців Колядки чи Щедрівки, в яких співається про робітничі гурти, збирані згідно полів і працюючі поруч себе, роблять вражіння пізніших культурно. IV. Що в Полі-Полі близько Дороги Ой там N.N. Арлами оре Арлами оре Стрєлкою сєє Стрєлкою сєє Лучком валочить Лучком валочить да й Бога просить Й уради Боже, Жито Густеє Жито Густеє Каласистьоє Поставим Женцуов Семсот Маладцуов Нажнемо Куопак ''к на Небі Зуорак Поставим Стажок Залатенький Вершок Образець очевидячи пракультурний: стрілецтво покривається з первісним рільництвом. Стрілець сіє зерно при помочи стріли як копача, волочить, — засуває засіяне, — лучком. Первісне, степове, поле орали Вірли своїми міцними кігтями, присідаючи серед Степу. Золотий Вершок мабуть натяк на Місяця. Вислів "Сімсот Молодців", попри Місячну символіку, все-таки говорить про великий гурт робітників, самих Хлопців, які очевидно заступали в рільній роботі жіноцтво в ці первісні часи, коли може й не було конечної потреби послугуватися жіноцтвом, — або, коли жіноцтво верховодило. Дальші дві Колядки потверджують попередню кінцеву заввагу: V.................................. Ой та ще будем Бога просити Бога просити Женців збирати Зберемо Женців Сімсот Молодців Гей то Молодці Добиранії! VI.................................. Зберемо Женці Женці-Молодці Самі Молоді Молоді Хлопці (Слово "женці" неоднозначне: женці — парубки для оженіння, женці — ті, що жнуть у полі. Обидва смисли переплітаються.) (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Листки з приводу цієї Пісні: Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Українська Астрально-мітольоґічна реліґійна концепціяр. Бог, Різдво Світа, Дідух і Лицарі. Традиції самогуртування: Cвятий Збір. Самогуртування: статеві, вікові та станові гурти. Статеві гурти для рільних робіт: пракультурні образці. Стежки до листків про Українські традиції.','Ой в Чистім Полі на Оболоні

