INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_729464','Щедрик Щедрик Щедрівочка (3)','Українська народна пісня. Виконує: Чарівна, Хор Сяйво, Гурт Friends in Kharkiv','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Що за Пташка? Про яку Кошару співається? Про яких Овечок і Ягничок? І хто їх Господар? Чи не з таких Пісень зродились народні загадки про Місяць і Зорі, про Нічне Небо...? Колядка стародавня: Українське Різдво Світа. Тай начала щебетати Господаря викликати. Читати листки з приводу цієї Пісні: Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Святий Вечер 6.01 — властиве Свято Різдва-Коляди. Свята, Тайна, Вечеря 6.01 — Як її підготувати і що вона означає? Стежки до інших листків про Українські традиції.','Щедрик-щедрик-щедрівочка
Прилетіла Ластівочка
Стала собі щебетати
Господаря викликати

Вийди-вийди Господарю
Подивися на Кошару
Там Овечки покотились
А Ягнички народились

В Тебе Товар весь хороший
Будеш мати мірку грошей
Хоч не гроші то полова
В Тебе Жінка чорноброва','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:narodni'', ''cat:philosophic'', ''cat:shchedrivky'', ''Колядки'', ''Народні пісні'', ''Філософські пісні'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_729464'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_729464','Щедрик Щедрик Щедрівочка (3)','Щедрик-щедрик-щедрівочка
Прилетіла Ластівочка
Стала собі щебетати
Господаря викликати

Вийди-вийди Господарю
Подивися на Кошару
Там Овечки покотились
А Ягнички народились

В Тебе Товар весь хороший
