INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7303446','Ми бурлаки як один',NULL,'uk','ukr_ssr_1919_1991',NULL,'1947','аудіозапис','Мандрівна пісня Куріня ст.пластунів "Бурлаки", створена 1947 року на еміґрації.','Ми бурлаки як один,
З серцем вічно молодим.
В світ ідемо, в світ ідемо,
В світ ідемо, як у дим!..

В нас відзнака - черевик,
А "мандруй" - бурлацький клик,
Ясне сонце, срібний місяць -
Наших мандрів провідник!..','[''pisni.org.ua'', ''cat:plastovi'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7303446'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7303446','Ми бурлаки як один','Ми бурлаки як один,
