INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7290767','Тихо в Аравії росами ранніми','Українська народна пісня. Виконує: Церква "Віфанія", Ансамбль Львів','uk','ukraine_before_1917',NULL,NULL,'http://bmyr.kiev.ua/music/text.php?ID=375&lang=ua','Пісню виконує Церква "Віфанія", Львів.','Тихо в Аравії росами ранніми
Там простягається путь.
Яків з родиною степом, пустинею           |
На батьківщину ідуть.                     | (2)

Тихо в Аравії росами ранніми
Тільки що сонце зійшло.
Здалека воїни страшно озброєні -          |
Військо Ісава ішло.                       | (2)

Двадцять років пройшло, миру як не було...
Брат був неначе той звір.
З братом зближається, знищить збирається, |
Якова цілий табір...                      | (2)

Яків в минулу ніч із Богом мав зустріч,
Серцем своїм сокрушивсь
Тяжко зітхаючи, Бога благаючи...          |
Бог його благословив.                     | (2)

Тихо в Аравії росами ранніми
Поперед війська Ісав.
Яків, кульгаючи, брата стрічаючи          |
Сім раз на землю упав.                    | (2)

Браття стрічаються, раптом щось сталося.
Перемінився Ісав.
Меч свій відкинувши, до брата кинувся,    |
Ніжно його обіймав.                       | (2)

Плакали воїни, військо озброєне,
Плакали діти й жінки.
Браття мирилися й перемінилися            |
Їхні серця і думки.                       | (2)

Тихо в Аравії росами ранніми
Там простягається путь.
Яків з родиною степом, пустинею           |
До Ханаану ідуть...                       | (2)','[''pisni.org.ua'', ''cat:christian'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7290767'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7290767','Тихо в Аравії росами ранніми','Тихо в Аравії росами ранніми
