INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7302848','В ніч на Купала','Музика: Юрій Дерський Слова: Г. Чорноволос. Виконує: Христина Охітва','uk','ukraine_before_1917',NULL,NULL,'авторське подання',NULL,'В місячну ніч на Івана Купала
В лісі кохання русалка шукала,
Дзвінко співала грішниця вічна
Пісню призивну в ніч чарівничу.
В ніч на Купала, в ніч солов''їну,
Папороть-цвітом вбралася дівчина,
Звабила душу і загубила
Квітки жагуча пристрасна сила.

В ніч на Купала!.. В ніч на Купала!..
В ніч на Купала!.. В ніч на Купала!..

Голосом ніжним причарувала,
Залоскотала, ой, зацілувала.
Серце гаряче кинула в роси
Диво-красуня зеленокоса.
Руки в''язала гіллям вербовим,
Щастям поїла гірким медовим,
Мятой-духами заполонила
Ночі казкові стомлена сила.

В ніч на Купала!.. В ніч на Купала!..
В ніч на Купала!.. В ніч на Купала!..

Надто кортока ніч на Купала,
Не доловила, ой, не доспівала,
Щезла, пропала, запискотіла
В омуті чорнім дівчина мила...

В ніч на Купала!.. В ніч на Купала!..
В ніч на Купала!.. В ніч на Купала!','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7302848'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7302848','В ніч на Купала','В місячну ніч на Івана Купала
В лісі кохання русалка шукала,
Дзвінко співала грішниця вічна
Пісню призивну в ніч чарівничу.
В ніч на Купала, в ніч солов''їну,
Папороть-цвітом вбралася дівчина,
Звабила душу і загубила
Квітки жагуча пристрасна сила.

В ніч на Купала!.. В ніч на Купала!..
В ніч на Купала!.. В ніч на Купала!..

Голосом ніжним причарувала,
Залоскотала, ой, зацілувала.
Серце гаряче кинула в роси
Диво-красуня зеленокоса.
Руки в''язала гіллям вербовим,
Щастям поїла гірким медовим,
Мятой-духами заполонила
Ночі казкові стомлена сила.

В ніч на Купала!.. В ніч на Купала!..
В ніч на Купала!.. В ніч на Купала!..

Надто кортока ніч на Купала,
Не доловила, ой, не доспівала,
Щезла, пропала, запискотіла
В омуті чорнім дівчина мила...

В ніч на Купала!.. В ніч на Купала!..
В ніч на Купала!.. В ніч на Купала!');
