INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7304262','Миколай!','Музика: Тарас Питлик Слова: Тарас Питлик. Виконує: Тарас Питлик','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Миколай! Миколай!
