INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_731343','А в Городі а в Городі Роман родить','Українська народна пісня. Виконує: Ніна Матвієнко, Тріо "Золоті Ключі"','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаївки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаївки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... Кругом Нього зелененько всередині веселенько. Листки з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Гаїлка-Великдень — Українське Свято Відродження Світа. Стежки до інших листків про Українські традиції. Гадаю, що ми виживаємо завдяки силі нашої культури. Ми виживаємо завдяки нашій духовності, вкоріненій у землю. Ми виживаємо завдяки доброті, незлопам''ятності та щедрості, які притаманні нашій пісенній вірі. – Стара людина.','А в Городі а в Городі Роман родить
А до мене Хлопець хо...

Роди-роди роди-роди Романочку
Ходи Хлопче щораноч...

Казав Роман казав Роман родить буду
Казав Хлопець ходить бу...

А в Городі а в Городі Роман Зілля
Кличе Хлопець на Весі','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_731343'), datetime('now')),datetime('now'));
