INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7318363','Перерва','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Кожен ранок на світанку
На шкільний поріг іду.
Тут багато я дізнаюсь.
Друзів щирих я знайду.
Ми малюєм і читаєм,
Справ багато має клас.
Тільки знову про перерву
Мріє кожен раз у раз.

Приспів:
Знов дзвінок сміється,             |
Пісня його ллється -               |
І за мить чарівну оживає клас.     |
Всі це слово знають і її чекають.  |
Бо перерва - справжнє свято в нас! | (2)

Починається перерва -
І вирує все навкруг.
Це вона без перебільшень
Школяреві кращий друг.
Хтось стрибає, наче м''ячик,
Хтось підспівує пісні,
Хтось із серденьком записку
Знову передав мені.

Приспів.

Довго тягнуться уроки,
А перерва збігла в мить.
Дуже тяжко непосилям
У такім режимі жить.
Ми благаємо дорослих,
Зрозуміти просим нас.
Між перервами уроки
Будуть хай тепер у нас.

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7318363'), datetime('now')),datetime('now'));
