INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7310343','Вальс випускників','Музика: Сергій Голоскевич Слова: Олександр Печора','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Щемна настала пора -
В школу пішла дітвора.
Стала найближчою враз
Вчителька перша для нас.
Щедро плекаючи квіт,
Очі розкрила на світ.
Важко ростили-годили батьки,
Швидко летіли роки,
Швидко летіли роки...

Приспів:
Ген, куди б не вели нас дороги,
Не стелилися в світ рушники,
Та на отчий поріг знов і знову
Линуть вдячні його боржники.
Повертають до рідної школи,
Мов птахи до гнізда, крізь роки.
Не забудуть ніде і ніколи,
Не замінять довіку ніким,
Не замінять довіку ніким...

Досі ми, майже щодня,
Роздобували знання.
Будні і свята були.
Як же ми буйно цвіли!
Знали, настане для нас
Надто хвилюючий час  -
Вечір останній святково-сумний,
Вечір шкільний випускний,
Вечір шкільний випускний...

Приспів.

Кличе до класу дзвінок.
Знову і знов на урок.
Щоб дітлахи залюбки
В світ протоптали стежки.
Хай не вмовкає віки:
"Здрастуйте, випускники!"
Хай кружеляє-окрилює нас
Найнезабутніший вальс!
Найнезабутніший вальс!

Приспів','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7310343'), datetime('now')),datetime('now'));
