INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_730969','Ой в Ліску в Ліску на Дубку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с. 3. Пісні з Волині. Упорядкування текстів та примітки О. Ф. Ошуркевича. Упорядкування нотних матеріалів М. С. Стефанишина. - К.: Музична Україна, 1970. - 336 с.','Колискові: Світові-Дитині. Пара - любощі: Лісок-Дубок. Колиска на Шнурку. Петруньо-Татко-Дівойка. Шитий Рукавець - Гуляння. Вибір Пари. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Були Світилки Яснії Зірки. Висіла Колисонька на Шнурку. На тій Гільци гей Колисочка. Йа в Чистім Поли стоїть Яблінка На Горі Сосна Золоторясна Ой в Ліску в Ліску на Дубку Ой колишу Дома лишу Дитину Маленьку Ой там у Ліску на Кленку висить Колиска із Шовку Там повісив Хлопчина Гойдалку. Ой в Ліску в Ліску на Дубку Ой у Лісі й у Лісі на Дубку Ходить Котик по Плоточку. По чім Його ви так упізнали. Шиє-малює Злотом гаптує. Шитим Рукавцем махає. Листки з приводу цієї Пісні: Українські релігійні роздуми про Бога. Українська Астрально-мітольоґічна реліґійна концепція. День реліґійно-філософських роздумів на Астральні теми, Варвари 17.12. Бог, Різдво Світа, Дідух і Лицарі. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Що означає ім''я "Коляда"? Стежки до листків про Українські традиції.','Ой в Ліску в Ліску на Дубку
Висіла Колисонька на Шнурку
В тій Колисоньці Петруньо
А Коло Його Татко Його

Шибай мене Татойко високо
Нехай я зобачу далеко
Там десь Моя Дівойка гуляє
Шитим Рукавцем махає','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_730969'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_730969','Ой в Ліску в Ліску на Дубку','Ой в Ліску в Ліску на Дубку
