INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7304343','Новая радість світу ся з''явила','Виконує: Нескорені','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Новая радість світу ся з''явила:
Пречиста Діва Сина породила.

Во Вифлеємі місті вельми рано
Христа витати пастирям казано.

Звізда услугу тую відправляла!
Царів персидських к Ньому проводжала.

Принесли Йому миро, ливан, злато.
Взяли заплату небесную за то.

Ірод злостивий з того засмутився,
Що Цар предвічний на світ народився.

Казав воїнам повсюди шукати,
Впень отрочата дволітні стинати.

Йосиф-старець Марію забирає
І до Єгипту з Христом утікає.

Нехай же Ірод вічно погибає!
Наш Цар рожденний всіх нас потішає.

Ми нині о Нім гойно веселімся.
Рождеству Його низько поклонімся.

Щоби нам зволив щасливий вік дати,
А по смерти з Ним в небі царствувати','[''pisni.org.ua'', ''cat:halycki'', ''cat:kolyadky'', ''Пісні з Галичини'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7304343'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7304343','Новая радість світу ся з''явила','Новая радість світу ся з''явила:
