INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_731565','Гори, гори *','(Я люблю волю, простір, далечінь). Слова: А. Бігун. Виконує: невідомий виконавець','uk','ukraine_1991',NULL,NULL,'1. Самвидавний туристський пісенник "Де гори Карпати, де Писаний Камінь". - Літо, 1982.',NULL,'Я люблю волю, простір, далечінь,
Бо я бурлак з далеких поколінь,
В одному місці я не можу жить,
Іти у мандри все мене кортить.
Як заблищить лиш сонце в небесах,
Як зашумить вітрець по деревах,
То в тілі кров моя аж закипить,
Іти у мандри все мене кортить.
Приспів:
Гори, гори, життя бурлацькеє,
Життя байдуже, ах, ю_ нацькеє,
Царить над нами сила власная,
Горить усе любов прекрасная.
Мене не страшить буря ані грім,
Просторий світ - це є для мене дім,
Я мандрував по горах, долинах,
Голубе небо - це для мене дах.
Мене не спинить море, океан,
Мене не страшить навіть гураґан,
До невигод всіляких я привик,
Моє знам''я - подертий черевик.
Приспів.','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''cat:manrivni'', ''cat:plastovi'', ''Пісні про красу природи'', ''Пісні на мандрівну тематику'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_731565'), datetime('now')),datetime('now'));
