INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_731868','Ой, місяцю, місяченьку','Музика: народна Слова: Марійка Підгірянка','uk','ukraine_before_1917',NULL,NULL,'Самвидавний туристський пісенник "Де гори Карпати, де Писаний Камінь". - Літо, 1982.',NULL,'Ой, місяцю, місяченьку,
Срібнолиций стороженьку,
Що сторожеш ти?
Я сторожу цілу нічку     |
Гай і поле, ліс і річку, |(2)
І сільські ха_ти.        |

Ой, місяцю, місяченьку,
Срібнолиций стороженьку,
Хто є в тих хатах?
Там сплять діти в постілочках, |
Сон цілує їх по очках,         |(2)
Мріють мрії в снах...          |

Ой, місяцю, місяченьку,
Срібнолиций стороженьку,
Про що мрії ті?
Про край рідний, край єдиний,  |
Про майбутність України        |(2)
Снять діти мої.                |

Ой, місяцю, місяченьку,
Срібнолиций стороженьку,
Чи здійсняться сни?
Стануть діти підростати,       |
Україні помагати -             |(2)
І здійсняться сни!             |','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:kolyskovi'', ''cat:patriotic'', ''Дитячі пісні'', ''Колискові'', ''Патріотичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_731868'), datetime('now')),datetime('now'));
