INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7303969','Снилось мені ясне сонце','Слова: Марійка Підгірянка','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Снилось мені ясне сонце,
Що в хаті світило, -
А то лиш так моя мама
Дивилася мило.

Приснивсь мені легкий вітецерь,
Що пестив колосся, -
А то мені моя мама
Гладила волосся.

Снилась мені ягідочка,
Як мед солоденька,
А то мене цілувала
Мама дорогенька.

Снилося мені, що на крилах
Я вгору несуся, -
А то мене із постелі
Піднесла матуся.

Снились мені ангелики,
Що в рай мене несли,
А то мами ніжні ручки,
До серця притисли.

Снилось мені ясне сонце,
Що в хаті світило, -
А то лиш так моя мама
Дивилася мило.','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7303969'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7303969','Снилось мені ясне сонце','Снилось мені ясне сонце,
Що в хаті світило, -
А то лиш так моя мама
Дивилася мило.

Приснивсь мені легкий вітецерь,
Що пестив колосся, -
А то мені моя мама
Гладила волосся.

Снилась мені ягідочка,
Як мед солоденька,
А то мене цілувала
Мама дорогенька.

Снилося мені, що на крилах
Я вгору несуся, -
А то мене із постелі
Піднесла матуся.

Снились мені ангелики,
Що в рай мене несли,
А то мами ніжні ручки,
До серця притисли.

Снилось мені ясне сонце,
Що в хаті світило, -
А то лиш так моя мама
Дивилася мило.');
