INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7329161','Ой, гук, мати, гук','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1928',NULL,'Уснословесний жанр повстанська пісня Жанр (народне визначення) партизанська Місце побутування с. Лопушанка, Хащівська сільрада, Турківський район, Львівська область Респондент Савка Анастасія Олександрівна, 1928 р.н. Збирачі Винницька Ліля, Кльок Юлія, Маханець Лесик','Ой, гук, мати, гук,
Бандеровці йдут,
Попереду, хто їм на заваді,
Багнетами тнут.

Зібрались вони
У темні ліси
І чекають Стефана Бандеру
На раду собі.

Друг Бандера йде,
Як голуб гуде,
І сказав нам: "Слава Україні,
Як вам ся живе?"

Чи не зимно вам?
Чи не голодні?
Чи маєте ся у що убрати?
Чис''те всі здібні?

− Нам тут добре є,
Ми не голодні
І маємо ся у що убрати
І всі''смо здібні.

Комуну ріжте,
Поляків вішайте,
А ту славу, славу бандерівську
Не забувайте!','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7329161'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7329161','Ой, гук, мати, гук','Ой, гук, мати, гук,
Бандеровці йдут,
Попереду, хто їм на заваді,
Багнетами тнут.

Зібрались вони
У темні ліси
І чекають Стефана Бандеру
На раду собі.

Друг Бандера йде,
Як голуб гуде,
І сказав нам: "Слава Україні,
Як вам ся живе?"

Чи не зимно вам?
Чи не голодні?
Чи маєте ся у що убрати?
Чис''те всі здібні?

− Нам тут добре є,
Ми не голодні
І маємо ся у що убрати
І всі''смо здібні.

Комуну ріжте,
Поляків вішайте,
А ту славу, славу бандерівську
Не забувайте!');
