INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7328565','Щедрик','Українська народна пісня. Виконує: Rock-H (Рокаш)','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Щедрик, щедрик, щедрівочка,
Прилетіла ластівочка,
Стала собі щебетати,
Господаря викликати.

Приспів:
Ти лем пой до нас, будемо співати,
З нами в рокаши новий рік стрічати,
Новий рік стрічати, старий провожати!
Друже, пой до нас, будемо співати,
З нами в рокаши новий рік стрічати,
Новий рік стрічати, старий провожати!
Щедрик, щедрик, щедрівочка,
Прилетіла ластівочка,
Стала собі щебетати,
Господаря викликати:

- Вийди, вийди, господарю,
Подивися на кошару, -
Там овечки покотились,
А ягнички народились.

Приспів. (2)

Новий рік стрічати,
Старий провожати!..','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7328565'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7328565','Щедрик','Щедрик, щедрик, щедрівочка,
Прилетіла ластівочка,
