INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7331565','Карпатська вечірня','(Заплутались хмари в смереках). Музика: Катерина Міщенко Слова: Катерина Міщенко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Заплутались хмари в смереках,
