INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_732464','Івана Купала тай в Воду упала','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Пускання Вінків, обрядове Купання. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Листки з приводу цієї Пісні: Українські релігійні роздуми про Бога. Українська Астрально-мітологічна реліґійна концепція. До історії Свята Івана Купала. Івана Купала — це велике прадавнє Українське Свято з шануванням Світотворчої Астральної Пари, — Води й Вогню, — з многотою Старовіцьких містерій. Купальське Свято має дуже широкий духовно-релігійний світогляд і природно пов''язане з Різдвом Світа (Колядою) та Щедрим Вечором. В річному Колі ніч і день Івана Купала є дзеркальним відображенням Свят-Вечора і Різдва Світа. Ідеологію Свят Купала визначають Святоріздвяні ідеї Сотворення Світа, Світотворчого Вогню (або Сліз Господа Бога), який викликає розлиття животворних Світових Вод, Купіль Бога у тих Водах і пливання Прадерева. Івана Купала тай в Воду упала: Багатозначне — Хто Його купав і чому? Чому тоді Вона в Воду упала:-)? Або — Іва на Купала тай в Воду упала (опис обряду). Порівняти зі Святоріздвяною купіллю Господа Бога та Святовечірніми словами: На Свят Вечер родив''ємся, На Свят Вечер хрестив''ємся! Пречиста Діва на Золотім Крижмі мя держала, У Змієвім Озері мя купала! Народна віра в Бога і почуття близькости Бога. З господарських свят первісних народів виходить, що їх мотивом є також бажання народу усвідомлення собі того Найвищого Єства в природі, що дає їм спроможність життя, даючи їм земні плоди й худобу. І в слід за тим стає мотивом Свята реліґія вдяки для Найвищого Єства.... Святочні обряди, пісні та пляси народів природи зроджують у них ідею Бога. Вони є тими середниками, що викликують у народу почуття близькости Бога, яка є неодолимим бажанням народу і його потребою. А ми в Кривого Танцю йдем Танцю йдем Володар Володар й одчиняй Ворота Іва на Купала тай в Воду упала Місячні назви: Червець, Іюнь та Івана Купала. Крім господарсько-пасічничого значіння має Червець ще й мітологічне, яке не можна поминути мовчки: нарід лучить з тим місяцем свої Старосвіцькі вірування й обряди. Їх об''єктом є буйна ростинність, яка в тім часі виступає в своїй повній красі й силі, — а її творцями вважає нарід Вогонь і Воду, як первні природи, що спричинили Почин Світа, та все є чинними в природі. Вони нагадують народові в сім місяці містерії з Почину Світа, які обходив в Старосвітськім Святі Різдва і він їх поновлює в Вечір перед Івана Купала ігрищами з вогнем і водою. Правда, що формально ці обряди вже майже всюди понехаяні, але в традиції народній вони ще живуть і день 24 червця (ст. стилю), хоч формально це христіянське свято Різдва Івана Хрестителя, але в душі народу в цей день є все ще повно давньої містики і чару, які падуть на цілий той місяць. Зі Староукраїнськими мітичними традиціями сходяться в тім місяці мабуть і Староіранські. В Іранців цей місяць був присвячений зоряному ґенієві Tir — і споминові Сотворення звірят і води. Цей божок Tip був патроном (покровителем) пригожих дощів і вродливости ростин, та боронив нарід перед демоном посухи. Є ідейний звязок між Іранськими й Українськими традиціями. Молода черва пчільна може бути символом першої звіринности на земли; містерії на Івана Купала з пусканням на воду вінків з зелені з причіпленими горіючими світельцями, — це об''ява радости народу з буйного росту рослин, а вогонь з водою — це творча сила природи. Молодь, яка сама виключно бере участь у цих містеріях, є символом молодечости в природі, — а Іван Купало передовим представником молоді. Звертаю при цім увагу, що Іранське слово "yvan, — yuvan, — yun" (чит. иван, — юван, — юн) значить: 1) молодець; 2) молодий лицар; а український Іван в суті річи значить те саме; при тім укр. іменник "юнак" (архаїчне: юний) є також синонімом молодечости й молодецької бравости. (Порівняти Щедрівки, де мовиться то про Молодця, то про Іванка, все в Місячній символіці.) З того виходило би, що імя місяця Juni є не тільки Іранського походження, але ідеологічно не чуже й Українцям. "Юнь" могло би бути збірним від "юний", — в кождім разі може бути Українським народом інтуіційно, по-свойому зрозуміле. Українські первісні жертви "на Боже" та інші. Ідея первісних жертв є загально прийнятою і удержуваною Українським народом. І досі лучаться часто з Українськими християнськими обрядами жертви, так звані, "на Боже" (вислів може означати і — на, бери Боже): первінців худоби або овець, перших звоїв полотна (власного виробу).... Сюди належать загально поширені народні жертви хлібні, що-осені, як первісні подячні дари-жертви з осінніх зборів збіжжя. Нарід не покушає "нового хліба", — з нового зерна, — поки не принесе жертви хлібної до церкви (звичайно, на поминку за померлих). Чи хочеш Брате на Бога дати Прийшли до Брата раз у Рік Гості... Чи хочеш Брате на Бога дати До жертв первісних належать Віночки або Китиці з перших цвітів, приношені до церкви на освячення у визначніші літні й осінні Свята. Так само Віночки, пускані на воду в народне Свято Івана Купала. Івана Купала тай в Воду упала! Були Світилки Яснії Зірки. Порух пожертвування Віночків і пускання їх на воду в день Івана Купала є подвійний — це жертва цих перших рослин і цвітів, якими так тішиться і кожна людина і худібка серед літа — і це шанування животворної Води, без якої тої буйності і краси рослин не було б. Ой на Йвана Зілля рвала в Городі садила Миленькому на Колядку а й на Щедрівочку. Українська ідея в паленні вогнів на Івана Купала лежить правдоподібно в спаленні на жертву Богові перших пожитків літньої природи та в запобіганні Божої ласки і помочи на час грядучих жнив. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) До історії Свята Івана Купала. Останнє укріплення Українського духа. Пісні і в Піснях — сутність Українства. Саме в цьому полягає пісенна сила. Як пояснює в "Історії Українського Красного слова" Михайло Грушевський, Свято Різдва Світа та його Пісні — це останнє укріплення Українського духа, яке встояло і досі не впало, незважаючи на шалений тиск різноманітних і численних нападників, церковних та політичних, місцевих і чужоземних. Під захистом цього укріплення зібралися та згуртувалися всі інші Свята та Пісні, переважно розбиті як цільні сили на їх власних теренах. Єдиний наш духовний устрій. Щоб пізнати останки старої творчости, зв''язані з українським духовно-обрядовим кругом, найкраще пройти самим тим кругом, крок за кроком, пізнаючи останки старого світогляду. Річний круг — це заразом властиво єдиний наш духовний і релігійний устрій, який заховує якусь світоглядну цілість, передчасно розбиту і зруйновану новими церковними, царськими та комуністичними заходами. На жаль тільки, ми й цього нашого старого річного круга не маємо в його повному і чистому передхристиянському вигляді і мусимо рахуватись на кожнім кроці не тільки з спустошеннями і виломами, але і зі змінами, перебоями й переносами, спричиненими в старому устрої церквою і церковним календарем. Гострі заборони, напади, погрози, котрими духовенство било по святах, які не встигли себе зв''язати в той чи інший спосіб з святами християнськими, поставити свої останки під їх "протекторат" або асимілюватися з ними, — факт загально відомий. Від "Слова о казнех божих" до Івана Вишенського, і відти до ще новіших консисторських наказів маємо безконечний ланцюг цих церковних, єрархічних уїдань на народні свята взагалі, і особливо на ті, які носили на собі особливо яскраві прикмети Українського світогляду і зв''язані були з свобідним паруванням молодіжи. Настільки ця війна була успішна, що тепер ми тільки й можемо зміркувати, які великі прогалини поробила тут церква, знищивши одно, друге покривши і замінивши християнськими обрядами, третє звівши на чисті посмішки й пародії. Ті "русалії", про котрі говорить згадане "Слово", Великоднє "волочильне", "праздник діавольский на поле ісшедших з танцями і скоками" на св. Юрія, на котрі вдаряв Іван Вишенський, ті вінці, що "робились о клячінні та вночи на воду до річки носились" ("Супліка на попа"), переважно позникали так, що ледве зістався від них який слід. А що лишилося від величних Весняних і Купальських містерій? (За працею: Михайло Грушевський. Історія української літератури. Т. 1.) Три Гискри впало Три Морі стало. А в тім Озерці Сам Бог купався. На тім Листку написано Щедрий Вечір. Там Пречиста Діва свого Синочка купала. Івана Купала тай в Воду упала. Були Світилки Яснії Зірки. Не гинь Миленький дам Ти Радоньку. Висіла Колисонька на Шнурку. Там десь Моя Дівойка гуляє Шитим Рукавцем махає. Де Моя Дівчина гуляє з ким Вона Перстень міняє. Там повісив Хлопчина Гойдалку. Да чому ти Дівчино гуляти не йдеш А де Наше Купайло стояло Івана Купала тай в Воду упала Та ходила Дівчинонька по Межі. Мариночка Сестричка на Бережечку сиділа Ой ходила Уляночка по Межі Стояла Маринка на Межі Та ходила Дівчинонька по Межі Ходить Маруся понад Водою На Вулиці в''ють Купала на Йвана. То там Місяць і Сонейко сіяло. Котилося Деревце Через Наше Сельце. А з того Деревця строїли Церковцю. Стоїть Сосонка в Барвіночку. Стій Дубе Зелений на Дубові Жолуді. А де Наше Купайло стояло Котилося Деревце Через Наше Сельце Купала на Йвана що у Йвана Шуба Рвана Купалась Ластівочка купалась На Майдані на Риночку Наша Маринка Купалочка Наше Купайло з Верби з Верби (1) Наше Купайло з Верби з Верби (2) Ой Купало Розкупало Ой летіло Помело через Наше Село Ой ходила Уляночка по Межі Та ходила Дівчинонька по Межі Через наше Сельце везли Клен-Деревце Чом Ти Барвінку не стелишся Як горіла так палала. А палиме ми єй з Троякого Зілля. А де той Святий Ян що нам Три Огні клав. Тоді будем говорити кого маєм з ким злучити. А на Яна на Янонька горіла нам Собітонька На Святого Яна Собітку палиме На Святого Яна Собітку палиме (2) Ой на Яна на Янонька не палена Собітонька Ой Вінку Наш Вінку Хрещатий Барвінку Пливе Доля за Тобою. Пливи Вінок за Водою Піду в Садочок нарву Квіточок Гей на Івана гей на Купала Заплету Віночок заплету Шовковий Іване Іваноньку не переходь Доріжоньку На Майдані на Риночку стоїть Сосонка в Барвіночку Ой Вінку мій Вінку Ой на Івана тай на Купала Ой у Лісі й у Лісі на Дубку Чий же то Віночок плине по Воді Під Калиною Дівчина там Косу Русу чесала. На Розсвіті личенько вмивала. По Півночі Черевички взувала. Вже Весна воскресла. Панєньская Краса в Меду ся Купала. Купався Іван доведецця і нам. Наша Маринка Купалочка. Купала на Йвана купавсь Іван та в Воду впав Купалась Ластівочка купалась Наша Маринка Купалочка Мариночка Сестричка на Бережечку сиділа Ой за Гаєм ой за Гаєм за Дунаєм Ой Купало Розкупало Ой на Купайла на Івана Ой на Яна на Янонька не палена Собітонька Ой ходила Уляночка по Межі Піду в Садочок нарву Квіточок Сьогодні Купала а завтра Івана - Дівка-сирітка Та ходила Дівчинонька по Межі Що на Петра Хліб пекла а на Йвана вибирала Не кажи Коню що я втопився. Замочилася і втопилася. Купала на Йвана купавсь Іван та в Воду впав Піду в Садочок нарву Квіточок Сьогодні Купала а завтра Івана - Дівка-сирітка Не рубай Ти мене й у Суботоньку. Маринко Моя Дівко Чий же то Голос Лугом іде А ми Рутоньку посієм посієм Де ти Купайло ночувало Доле ж моя нещаслива - Коструб На Івана на Купайла Ой летіло Помело через Наше Село Сєріє Гусі Гречку поїли Стояла Маринка на Межі А на тій Вербі Рожеві Квіти. Буде тобі Квітка Красна. Ой на Городі Широка Квітка. Ой на Городі Широка Квітка Поставлю Сторожу тай посію Рожу Ходить Маруся понад Водою Буде Тобі Три Дорозі. Коня напуває личко умиває. Грай Кониченьку Сивий Маленький зо мною. Сволока тече в Хаті Болото Там за Горею за Високею Ой приїхав під Нові Ворота. А де Наше Купайло стояло Ой біжит Коник під Гречкою Ой що то іде Селом Cелом Поскакав Коник попід Гречкою Хтось у Борі гукає Тай зачали говорити кого мают з ким злучити. Ой Дівчино моя Галю Сім Загадок загадаю. А','Івана Купала тай в Воду упала
