INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_732161','Ми Голубку уловили','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002 2. Пісні з Львівщини. К.: Музична Україна, 1988. С. 27.','Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Піди принеси Святе Різдво. Мене перейшло Сиве Голуб''є. Вибирай си кого любиш. Забави з Паруванням, забави з Цілуванням. Цілуючись творять, відновлюють Ціле — Пару, зцілюються. Поцілувати, поцілити чи зцілити? Ціль — ціле? Зцілення — у цілому? Як цілишся — то зцілишся? Як питимеш з уст моїх, станеш, як я, а я стану тобою і що заховано відкриється. — Таємні Євангелія (Фома) Подруга Спасибога звалася Марія. Він її любив більше від інших учнів і часто цілував її ніжно у вуста. Інші учні обурювались і осуджуючи казали йому: "Чому ти любиш її більше від нас?". Ісус відповідав говорячи до них: "Чому я вас не люблю, як її?". — Таємні Євангелія (Филип) Ісус побачив немовлят, які брали груди. Він сказав учням своїм: "Цих малят, які ссуть, можна порівняти до тих, які ввійдуть до Царства." Вони запитали його: "Якщо ми станемо, як ці діти, чи ввійдемо ми до Царства?". Ісус повідомив їм: "Коли ви зробите з двох одне і коли ви зробите так, що те, яке всередині, буде назовні, а те, яке назовні, буде всередині, та що те, яке згори, буде знизу, і коли ви зробите так, що чоловіче й жіноче будуть одним, настільки, що чоловік не буде більше чоловіком, а жінка не буде більше жінкою, тоді ви ввійдете". — Таємні Євангелія (Фома) Буде тобі Квітка Красна. На Городі під Цибулькою Не стій Вербо над Водою Голуб/Голубка. Ми Голубку уловили Ми Голуба ізловили На Городі під Цибулькою Туман Яром по Долині Чорний Баран. Де же Ти був же Чорний Баране Де Ти ходив Наш Чорний Баране Де лес бив де лес бив Чорний Баране Муж/Жона. А хто видав а хто слихав Мою Жінку на Торгу А я Хліба напечу-напечу - Жона Царівна/Царевич. Жила-була Царівна (2) Жила-була Царівна (1) Ой жив та був Царевич-Царевич Царівно ми Тобі Гості Ти такий, як я, в тебе жовті сльози (Небо*) Ще Забави: Гра Перепілки. Ой у Перепілки та Голівка болить Гра Кота-Мишки. Втікай Мишко до Нори Золотої Комори Ой до Нори Мишко до Нори Ой Данчику Білоданчику поплинь. Правой ручкою обняла ще й поцілувала. Дівчина збуджує Парубка, а Парубок пробуджує Дівчину. Листки з приводу цієї Пісні: Еротичні містерії, тиждень від Катерини 7.12 до Калети — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні.','Дівчата і Хлопці, взявшись за руки, йдуть Колом з Піснею.
Всередині Кола стоїть Дівчина-Голубка.
Після закінчення в''язки вона вибирає собі з-поміж Хлопців Коханого. Обіймає й  цілує його.
В''язка повторюється, і вже Хлопець вибирає собі Дівчину-Голубку. Обіймає й цілує її.
Таким чином утворюється Друге Коло, яке крутиться в протилежний бік.
Після кожної в''язки всі зупиняються, а з початком Пісні йдуть у протилежний бік.

