INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7327363','Журавлі летіли в далечінь чужинну','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1963',NULL,'Уснословесний жанр повстанська пісня Місце побутування с. Жукотин, Лімнянська сільрада, Турківський район, Львівська область Респонденти Дребот Марія Миколаївна, 1963 р.н., Мацур Марія Степанівна, 1961 р.н. Збирачі Іванищук Марія, Беднарська Ружена','Журавлі летіли в далечінь чужинну,
Танула журливо пісня вдалині.
Прибула матуся на сумну гостину,        |
На могилу сина в дальній стороні.       | (2)

Ой, устань, озвися, любий мій синочку,
Змучену журбою неньку обніми.
Я для тебе, синку, вишила сорочку       |
І мережку кожну облила слізьми.         | (2)

Хай на ній не в''яне голубінь барвінку,
Листячко зелене, маки вогняні.
Я хотіла внуків годувать, синочку,      |
А стрічаю старість у самотині.          | (2)

Ось принесли квіти хлопці та дівчата,
Голови схиляють, мов своя рідня.
Сину, мій синочку, любий мій повстанцю, |
Я тебе додому ждатиму щодня.            | (2)

Журавлі летіли в далечінь чужинну,
Танула журливо пісня вдалині.
На могилі сина вишита сорочка,          |
На могилі сина маки вогняні...          | (2)','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7327363'), datetime('now')),datetime('now'));
