INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7330147','Бог біля тебе','Музика: Мар''ян Ганусяк Слова: Богдан Ковальчин, Мар''ян Ганусяк. Виконує: Арсен Мірзоян','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Зриваєш руками уламки,
Заклеєні очі сльозами,
Ще крок до свободи, до слави,
Ще мить - і загояться рани!
А смерть до землі тебе тисне
І кличе з собою до раю,
Та серце ще б''ється навмисне,
Бо вірою не залишає!

Приспів:
Бог біля тебе сонцем у небі,
Світлом в твоїх очах!
Бог біля тебе там, де й не треба -
Ти і не помічав!...

Над степом здригаються хмари
І сиплять землею додолу,
Кирпата в сталевих собаках
Наближує даль невідому,
І чорне обличчя з під каски
Без носа з приціла злітає,
Та віра не дасть тобі впасти,
Бо силою не залишає!

Приспів. (2)

Замовкла під пальцями зброя
Героя, що вже не вернеться,
Ніхто крім нас! Всі до бою!
Десант не здає, не здається!

Приспів. (2)

Бог біля тебе!','[''pisni.org.ua'', ''cat:ato'', ''Пісні російсько-української війни та АТО'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7330147'), datetime('now')),datetime('now'));
