INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_733745','Зима','Музика: Бумбокс Слова: Андрій Хливнюк. Виконує: Бумбокс','uk','ukraine_1991',NULL,NULL,NULL,'За матеріалами форумів','Зима, зима, зима, зима.
Зняла мої ручні гальма.
Чимось білим літо вбила.
Зима, зима, зима, зима.
Звела, зараза, з розума.
І не шкода голольода.
Я з ними, зими, зими.
По парадних стигли ми,
Невідомими, стали ми знайомими.
Довелося ще раз її бачити прикрас.
Біла кома на моїх балконах.

Приспів:
Питаю я як
Тепер відшукати себе.
Питаю я де
Того, що було вже не буде.
Ти визначи час.
Ніколи, а може ще раз.
Невдовзі зима занесе
Все, що так зігрівало нас.

Холодний, модний, водний тік.
Від неї біг, до тебе втік.
Кучугури, так як ти не журять.
М''яка, мов пір''я і легка
Одвічна матиматика.
Врахувала, щоб тепла не стало.
Зима, зима, зима, зима.
Моя кохана і кума.
Приспали, не забули ми.
Білі впали килими.
Зима, зима, зима, зима
Звела зараза з розума
Біла кома на моїх балконах

Приспів.','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_733745'), datetime('now')),datetime('now'));
