INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7329464','Прийшла карта до тата','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'Фольклорний гурт "Печеніжинські молодиці".','Івано-Франківська обл., Коломийський р-н., смт. Печеніжин. Пісня на повстанську тематику про події національно-визвольних змагань першої половини ХХ ст.','Прийшла карта, до тата, до тата,
Прийшла карта до тата:
Давай сина, до війська, до війська,
Давай сина до війська.
А я сина, не маю, не маю,
А я сина не маю,
Старшу дочку, вам даю, вам даю,
Старшу дочку вам даю.
А я тату, не піду, не піду,
А я тату не піду,
Воювати, не буду, не буду,
Воювати не буду.
Бо я серця м''якого, м''якого,
Бо я серця м''якого,
Не уб''ю я ворога, ворога,
Не уб''ю я ворога.

Прийшла карта, до тата, до тата,
Прийшла карта до тата:
Давай сина, до війська, до війська,
Давай сина до війська.
А я сина, не маю, не маю,
А я сина не маю,
Молодшу дочку вам даю, вам даю,
Молодшу дочку вам даю.
А я тату, я піду, я піду,
А я тату я піду!
Воювати я буду, я буду,
Воювати я буду!
Бо я серця твердого, твердого,
Бо я серця твердого!
Та й уб''ю я ворога, ворога,
Та й уб''ю я ворога!
Як їй коси втинали, втинали,
Як їй коси втинали,
Усі хлопці плакали, плакали,
Усі хлопці плакали.
Як їй коня сідлали, сідлали,
Як їй коня сідлали,
Всі дівчата плакали, плакали,
Всі дівчата плакали.
Як їй шаблю давали, давали,
Як їй шаблю давали,
Батько й мати плакали, плакали,
Батько й мати плакали...','[''pisni.org.ua'', ''cat:povstanski'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7329464'), datetime('now')),datetime('now'));
