INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7350848','Не дала','Музика: Роман Микульський Слова: Борислава Білоцерківська. Виконує: Андріана','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'НЕ сиділось мені вдома,
