INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7348745','Про них','Музика: Віктор Винник Слова: Віктор Винник. Виконує: Віктор Винник, Мері','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Світ накриє перший сніг...

І коли настане ранок
Світ накриє білий сніг,
І земля загоїть рани,
Ми згадаємо про них!..
Про всіх...
Час застигне на хвилину
Й не поможуть тут слова,
А в очах його дитини
Так нестримно заблищить
Сльоза...

Приспів:
Про них
Співає вітер в полях!..
Про них
Запам''ятає земля!..
Їх шлях
Освітить рання зоря!..
Про них,
Кого забрала війна
За нас!..

День малює все на біло -
Подивись, яка краса!
Тут не чути як ридають
Від обстрілів небеса,
Небеса...
І коли настане ранок
Світ накриє перший сніг,
І земля загоїть рани,
Ми згадаємо про них!..
Про всіх!..

Приспів.

Речитатив:
Коли розпочалася ця війна
Тисячі патріотів зі зброєю в руках
Стали на захист Батьківщини!
Вони залишили свої родини і роботу,
Щоб щоденно, ризикуючи життям,
Боронити країну від підступного ворога.
Вони воюють не за гроші і не за славу,
Їхня ціль - сильна і незалежна Україна!
Багато з них вже віддали за це своє життя,
Вони - добровольці!

Приспів.','[''pisni.org.ua'', ''cat:devoted'', ''Пісні присвячені окремим особам'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7348745'), datetime('now')),datetime('now'));
