INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7354363','Пісня мами нареченої','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'В мене народилась дочка,
А хотіла я синочка,
І сьогодні я щаслива,
Бо я маю вже і сина!
Тож вітаю я вас, діти,
Буду я за вас радіти!
Хочу, щоб щасливі були
І мене ви не забули!

Приспів:
Для вас, любі мої діточки,
Для вас усі найкращі квіточки!
Рідненькі, будьте ви щасливенькі!
Живіть в любові і коханні ви,
Щоб були в вас і дочки, і сини!
Люблю вас і прошу Бога берегти,
Пливіть, як лебідь і лебідонька!
Живіть, як голуб і голубонька,
На радість Богу, людям і мені!

Щоб ви були здоровенькі
І обоє щасливенькі!
Коло мене, щоб ви жили,
Я допоможу вам щосили!
Подарунки, щоб дарили
І ніколи не скупились,
Діточок для нас ростили,
До ста літ в багатстві жили!

Приспів.

На радість Богу, людям і мені!','[''pisni.org.ua'', ''cat:vesilni'', ''Весільні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7354363'), datetime('now')),datetime('now'));
