INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_735549','Батькове серце','Музика: Анатолій Пашкевич Слова: Дмитро Луценко. Виконує: Дмитро Гнатюк','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Воронки й окопи давно заросли полинами,
А в мене ще й досі не гоїться болю клубок.
Схвильований батько край шляху прощається з нами
І лагідно просить:
— Ти слухайся мами, синок!
Ми поле орали, в нужденних брели посторонках,
І крепом лягала за нами життя борозна.
Як море пекуче, прийшла і до нас похоронка,
І в мамині коси вплелася в той день сивина.
Та я все не вірив і тата ходив виглядати,
Хотілось відчути тепло його добрих долонь.
А батьку судилось і в День Перемоги лежати,
На кручах Дніпрових пала з його серця вогонь.
Приходжу до нього тепер я з своїми синами,
Не зміряти болю й прогірклого щастя мого.
Воронки й окопи давно заросли полинами,
А батькове серце палає, як вічний вогонь','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_735549'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_735549','Батькове серце','Воронки й окопи давно заросли полинами,
А в мене ще й досі не гоїться болю клубок.
Схвильований батько край шляху прощається з нами
І лагідно просить:
— Ти слухайся мами, синок!
Ми поле орали, в нужденних брели посторонках,
І крепом лягала за нами життя борозна.
Як море пекуче, прийшла і до нас похоронка,
І в мамині коси вплелася в той день сивина.
Та я все не вірив і тата ходив виглядати,
Хотілось відчути тепло його добрих долонь.
А батьку судилось і в День Перемоги лежати,
На кручах Дніпрових пала з його серця вогонь.
Приходжу до нього тепер я з своїми синами,
Не зміряти болю й прогірклого щастя мого.
Воронки й окопи давно заросли полинами,
А батькове серце палає, як вічний вогонь');
