INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_733969','Ой завіяли Буйні Вітрови','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Старий і Новий Рік: Маланкова. Стародавні Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Радуйся Земле Коляда їде! Читати листки з приводу цієї Пісні: Що означає ім''я "Коляда"? Що означає "Дідух"? Співаймо Світові-Дитині: Колядки, Щедрівки, Колискові... Стежки до інших листків про Українські традиції.','Ой завіяли Буйні Вітрови
Сему Дворові Новому Року пригнали       | (2)

Встань Ґаздо вгорі Новий Рік в Дворі
Пускай Старий Рік приймай Новий Рік до себе | (2)

Уставай Ґаздо не протягайся
Новому Року з нами вклоняйся скоренько  | (2)

Нам за Коляду дайте Ковбасу
Щоби-сте мали Долю Хорошу дай Боже      | (2)

На рідну школу дайте по грошу
А Молодцеві по Колачеві не шкодить      | (2)

Дай же вам Боже з сим Новим Роком
Щастя-Здоровлє за кожним Кроком желаєм  | (2)    Заспів (mp3)','[''pisni.org.ua'', ''cat:shchedrivky'', ''Щедрівки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_733969'), datetime('now')),datetime('now'));
