INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7350240','Колобок','Музика: Олександр Шевченко Слова: Олександр Шевченко','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Уляна Петрик, колектив "Диво", церква Вознесіння Господнього.','Котиться, котиться лісом Колобок,
Він утік від баби з дідом.
Котиться, котиться з боку на бочок,
Пісенька лунає слідом!

Приспів:
Пісеньку цю знаємо,
Разом заспіваємо,
Разом заспіваємо:
Я від баби утік,
І від діда я утік,
Колобок, колобок,
Рум''янесенький бочок!
Я від баби утік,
І від діда я утік,
І від тебе утечу!

Котиться, котиться із бочка на бік,
Бачить - зайчик-пострибайчик.
Раз! І від зайчика весело утік,
Швидко-прудко, наче м''ячик.

Приспів.

Котиться, котиться, щось, мабуть, шука,
А назустріч - вовчик-братик.
Він і від вовчика весело втікав,
Пісеньку свою співати!

Приспів.

Котиться, котиться з долу на горбок,
Зустріча його ведмедик.
Від косолапого втік наш колобок,
Нехай їсть малину з медом!

Приспів.

Котиться, котиться, хай йому щастить,
Бо лисичка десь гуляє,
Може, лінується, може, просто спить,
Колобка не зустрічає.

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7350240'), datetime('now')),datetime('now'));
