INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7358343','Дорога додому','Музика: Микола Янченко Слова: Микола Янченко','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Тетяна Денисюк.','Знову іду знайомими стежками
В радість, чи біду до тебе,
Моя мамо!
Тобі я низько поклонюся,
Як у дитинстві пригорнуся!

Приспів:
Дорога додому,
До рідного краю дорога,
Де мати чекає завжди
Край воріт!
Чи радість на серці,
Чи в душу запала тривога,
Ідемо до мами
І будемо йти сотні літ!
Бо все найдорожче на світі,
То мамині очі,
Усмішка ласкава,
Як квітів нев''янучий цвіт!
Ідемо до мами
В ті сонячні зоряні ночі,
Ідемо до мами,
Пройшовши весь світ!

В ранню весну і сивою зимою
День і ніч іду
Зустрітися з тобою!
Стежка до мами,
То зоряна ниточка долі,
Яка не загубиться
Серед волошок у полі!

Приспів.','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7358343'), datetime('now')),datetime('now'));
