INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_736363','Сіяв батько жито','Музика: Іван Карабиць Слова: Вадим Крищенко. Виконує: Медобори','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Сіяв батько жито,
Де поля зірчасті,
Щоб усім нам жити
У добрі і щасті.
І садила квіти
Біля вікон мама,
Щоб краси у світі
Не було замало.

Приспів:
Для людей відкрита
Хата наша біла,
Тільки б чорна кривда
В неї не забігла.
Хліб ясниться в хаті,
Сяють очі щирі,
Щоб жилось по правді,
Щоб жилось у мирі.

Золотиться колос,
Ллє зерно на руки,
Ніби батьків голос -
До дітей і внуків.
Мальви й чорнобривці
Розрослися рясно,
Начебто гостинці
Маминої ласки.

А дорога кличе
На чотири боки,
Мамине обличчя
Засльозив неспокій.
Доброї поради
Чую звуки щирі,
Щоб жилось по правді,
Щоб жилось у мирі','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_736363'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_736363','Сіяв батько жито','Сіяв батько жито,
Де поля зірчасті,
Щоб усім нам жити
У добрі і щасті.
І садила квіти
Біля вікон мама,
Щоб краси у світі
Не було замало.

Приспів:
Для людей відкрита
Хата наша біла,
Тільки б чорна кривда
В неї не забігла.
Хліб ясниться в хаті,
Сяють очі щирі,
Щоб жилось по правді,
Щоб жилось у мирі.

Золотиться колос,
Ллє зерно на руки,
Ніби батьків голос -
До дітей і внуків.
Мальви й чорнобривці
