INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7366363','Миколай','Слова: Стефанія Лепех','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує тріо священників "Новий Час".','Зберігає пам''ять з дитячих днів
Образ Миколая, що на стіні.
Із ікони повсякчас
Пильно дивиться на нас.
Твоя ікона на стіні,
Від тебе милості чекаю.
Ти посміхаєшся мені,
Святий мій Отче Миколаю! | (3)

За всі добрі справи, що ти творив,
В Бога ласки в небі ти заслужив!
Чи зумів би так, як ти,
Я свій шлях в житті пройти?..
Твоя ікона на стіні,
І в серці я собі бажаю:
Щоб посміхатись людям всім,
Я мушу стати Миколаєм!   | (3)

Знаю я, ти добрий є Миколай,
Помолись за наш український край!
Дар нам щедрий принеси,
В Бога ласки попроси!
Твоя ікона на стіні,
Від тебе милості чекаю.
Ти посміхаєшся мені,
Святий мій Отче Миколаю! | (3)','[''pisni.org.ua'', ''cat:svyatyy-mykolay'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7366363'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7366363','Миколай','Зберігає пам''ять з дитячих днів
