INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7360147','Зайчик і Мишка','Слова: Зоряна Лісевич','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує Тетяна Саницька (колектив "ДИВО", церква Вознесіння Господнього, керівник - Тетяна Годій).','Зайчику й Мишко,
Куди тишком-нишком
Із дому бігом біжите?
Пограймо, звірятка,
В картинки спочатку.
А Зайчик і Мишка на те:
Вибач, та нині
Йдемо на гостину
В палац із рожевого скла.
Нас лялька Каміла
На чай запросила
І тістечка з кремом спекла!

Зайчику й Мишко,
Куди тишком-нишком
Із дому бігом біжите?
Побавтесь обоє
В принцеси зі мою.
А Зайчик і Мишка на те:
Раді б, та, схоже,
Сьогодні не зможем.
Пробач, але відповідь: "Ні",
Бо ми поспішаєм
Послухати в гаї
Вечірній концерт цвіркунів.

Зайчику й Мишко,
Куди тишком-нишком
Із дому бігом біжите?
Вертайтесь, будь-ласка,
Послухати казку,
А Зайчик і Мишка на те:
Люба дитино,
Вже пізня година,
Вкладатися в ліжко пора!..
Вже місяць на небі -
І спатоньки треба,
Добраніч... Добраніч...
Добра...','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:kolyskovi'', ''Дитячі пісні'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7360147'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7360147','Зайчик і Мишка','Зайчику й Мишко,
