INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_736745','Ой Весна Весна тай Весняночка','Українська народна пісня. Виконує: Веснівка','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави. Вже Весна воскресла. Погнала Бичка за Ворітечка.','Ой Весна-Весна тай Весняночка
Приспів за зразком:
Ой рано-рано тай Весняночка

Де ж Твоя Дочка тай Паняночка
Погнала Бичка за Ворітечка
Піймала Бичка та за Ріжечки
Пасися Бичку я спряду Мичку
Старому Діду на Рукавичку
А Бабусеньці тай на Спідничку
Мички не спряла Бичка втеряла
Ой Весно-Весно-Весняночко
Де Твоя Дочка Паняночка
Та піймали Бичка та за Ріжечки
Ой пасися Бичку поки спряду Мичку
Своєму Братові на Рукавичку
Бичок пасеться Мичка прядеться
Бичок напасся Мичка спрялася

Ой Весно-Весно да Весняночко
Де Твоя Дочка да Паняночка
Десь у Садочку шиє Сорочку
Шовком да Біллю да вишиває
Своєму Силому пересилає
Надівай її щонеділеньки
Споминай же мене щогодиноньки
Шовком я шила а Біллю рубила
Жаль мені Козака що я полюбила','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_736745'), datetime('now')),datetime('now'));
