INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7364262','Коломийки на біс','Музика: Володимир Шинкарук Слова: Володимир Шинкарук. Виконує: Володимир Шинкарук','uk','ukraine_1991',NULL,NULL,'https://pisennyispas.com/%d0%b2%d0%be%d0%bb%d0%be%d0%b4%d0%b8% d0%bc%d0%b8%d1%80-%d1%88%d0%b8%d0%bd%d',NULL,'Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
Час летить, і ми з роками змінюємо звички:
Старість це коли аптечка більша косметички!

Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
Я борги свої ніколи не віддам нікому -
Пригодяться такі гроші і мені самому!

Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
А студентський гуртожиток знову сповнений
Пісень: у студентів є два свята -
День студента й... кожен день!

Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
У коханні третій - зайвий, будемо відверті:
Чоловік застукав жінку... молотком до смерті!

Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
У коханні третій - зайвий, я скажу не без підстав -
Чоловік "застукав" жінку... ну а потім - "задовбав"...

Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
Час займатися собою з вечора й до рання,
Бо дорожче від здоров''я тільки лікування!

Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
А виборчі перегони на те й перегони -
Перемогу здобуває той, хто більше "гонить"!

Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
Це, повірте, щира правда - всі жінки, як Інтернет:
І учора, і узавтра комусь - "соm", а комусь - "net".

Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
І діагноз був невірний, і рецепт неточний,
Бо хірург кінчав вечірній, фармацевт - заочний...

Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
Хоче знать крокодилятко, де крокодил-тато,
Каже мама: У посольстві, там він... дипломатом.

Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
Проживаємо ми дні, як листя на гілці,
Якщо істина - в вині, то правда - в горілці!

Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!
Для людей найважливіші здоров''я і нерви,
А в коханні, як і в школі, головне - перерви!
Гей, шіді-ріді-дан! Шіді-ріді-дана-дана!
Гей, шіді-ріді-дан! Шіді-ріді-дана!','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7364262'), datetime('now')),datetime('now'));
