INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7366969','Колискова Україні','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Гнеться житечко до теплої землі,
Волошкова синь цілує босі ноги,
Я молюся, щоб тривоги і жалі
Не приходили на ці святі дороги.
Барвінковим цвітом знов стомився день,
Я благаю в Бога росяної долі,
Я сплету рясний віночок із пісень
І лишу його y золотистім полі.

Приспів:
Я співаю при долині колискову Україні,
На долонях y дитини засина моя земля
Наче тають полонини, українська пісня лине
В серце кожної дитини
Спи, маленький, - промовля...

Вже трембіти розбудили шум гаїв,
Ген, дуби стоять, як слава, віковічні.
Моя доле, не минай же ці краї,
Де мого народу сурми споконвічні!
Я бажаю, щоб вітала день новий,
І добра людського врода промениста,
І для тебе, найрідніший краю мій,
Хай лунає колискова ніжна пісня!

Приспів.','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7366969'), datetime('now')),datetime('now'));
