INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_737343','А в Кривого Танця та не виведем Кінця','Українська народна пісня','uk','ukraine_before_1917',NULL,'1862','1. Народні пісні в записах Степана Руданського. - К.: Музична Україна, 1972','За автографом: Відділ рукописів Інституту літератури ім. Т.Г.Шевченка АН УРСР, архів С.руданського, ф. 63, од. зб. 2. - Копа пісень. Списав Степан Руданський. Ялта, року 1862, м-ця червця. N 52. Гаївки-Великдень: Українське свято Відродження Світа. Гра-коловід Змії/Змія. Весна Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... А ми Йому Кінця не знайдем.','А в Кривого Танця
Та не виведем Кінця!

Треба Єго та й виводити,
Лад Йому та й наводити.

Ой Вулиця та й Широкая,
Чого Трава невисокая?

Бо Парубки та й істоптали
Великими та й Ножищами,

Великими та й Ножищами,
Подертими Постолищами!

Ой Вулиця та Вузенькая,
Чого Трава Зелененькая?

Бо Дівоньки та й істоптали
Маленькими Ноженьками,

Маленькими Ноженьками,
Червоними та Чобітками.

Червоними та Чобітками,
Золотими та Підківками','[''pisni.org.ua'', ''cat:podilski'', ''cat:vesnyanky-hayivky'', ''cat:zhartivlyvi'', ''Пісні з Поділля'', ''Веснянки та гаївки'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_737343'), datetime('now')),datetime('now'));
