INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7367262','Козацька слава','Музика: Володимир Макієвець Слова: Богдан Мельничук','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує Микола Довгальов.','Вічний і далекий той козацький шлях,
Лине, лине слава добра у віках!
Стихли звуки бою - козаки ідуть,
Сотні літ минуло - в пам''яті живуть!

Приспів:
Батьку-отамане, нас веди вперед!
Слава не зів''яне - крил широких лет!
Чуєш нас, Богдане? - Чую вас, агов!..
В наших жилах грає молодеча кров!

Шляхом йдуть чубаті - хлопці хоч куди!
Гей, до лав козацьких можеш стати й ти!
Писарю наш вірний, запиши й мене!
Вірим, що козацька слава не мине!

Приспів.','[''pisni.org.ua'', ''cat:kozacki'', ''Козацькі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7367262'), datetime('now')),datetime('now'));
