INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7368240','Добре серце','Музика: Світлана Тарабарова Слова: Світлана Тарабарова. Виконує: Світлана Тарабарова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Доброму, доброму серцю,
Доброму, доброму...

Щастя, здається це просто слово
Кожному знайоме,
Це новий світ, нове життя!..
Щастя ще зовсім крихітного зросту,
Обійми, коли не просто,
На вушко: Мамо, з тобою я!..
Мамо, з тобою я!..

Приспів:
А в нього добре серце!
Як сонце воно сміється!
Очі твої!..
Доброму, доброму серцю,
Доброму, доброму...
А в нього добре серце!
Воно тремтить,
Пташкою б''ється в мені!..
Хай світить йому
Лиш теплеє сонце!
Доброму, доброму серцю, |
Доброму, доброму серцю  |
Світить завжди          |
Лиш теплеє сонце...     | (2)

Щастя мені посміхається вранці,
Щічки ямочки, як у казці,
Очі татові в нього, так!
І не знаю любові сильніше на світі,
Обіймів міцніших на світі,
Щастя - це наші діти!

Приспів.

Доброму, доброму серцю,
Доброму, доброму серцю
Світить завжди
Лиш теплеє сонце...
Доброму, доброму серцю,
Доброму, доброму серцю...','[''pisni.org.ua'', ''cat:pro-ditey'', ''Пісні про любов до дітей'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7368240'), datetime('now')),datetime('now'));
