INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7359240','На гору Голгофу іде страдальна мати','(Страждальна мати). Слова: Марія Чайківчанка','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'На гору Голгофу іде страдальна мати...
Плаче, ридає, мліє від знущання ката...
Ой, сину, мій сину, моя надіє і утіхо!
Чом в''янеш квітом ранім на молодім віку?

Іду за тобою вслід у світ злобний і жорстокий...
Тебе катують, забивають цвяхом в тіло глибоко...
Ти в жертву віддався, щоб спасти людський рід...
Всиротив, як билину... Цілувати рани, твій слід...

Із малих літ тебе ростила материнською любов''ю
І оберігала, охороняла від гріз, вітрів твою долю,
А нині віддаю на страту, на розп''яття тебе, сину...
А ти в покорі ідеш на муки - і зближається година...

Зболене моє серце страждає дивитись на твої муки
Увінчаного у терновім вінку, до хреста прибиті руки...
О, мій Боже милий, змилуйся над зраненим сином!..
Дай перенести біль страждання у важку хвилину...

Між двома розбійниками на хресті розп''ятий...
Затьмарився білий день, затряслась земля мати...
Віддаю тебе, мій  сину, Небесному Отцю навіки!..
Помилуй, лукавий світ... Подай душі духовні ліки!..','[''pisni.org.ua'', ''cat:strasni'', ''Страсні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7359240'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7359240','На гору Голгофу іде страдальна мати','На гору Голгофу іде страдальна мати...
Плаче, ридає, мліє від знущання ката...
Ой, сину, мій сину, моя надіє і утіхо!
Чом в''янеш квітом ранім на молодім віку?

Іду за тобою вслід у світ злобний і жорстокий...
Тебе катують, забивають цвяхом в тіло глибоко...
Ти в жертву віддався, щоб спасти людський рід...
Всиротив, як билину... Цілувати рани, твій слід...

Із малих літ тебе ростила материнською любов''ю
І оберігала, охороняла від гріз, вітрів твою долю,
А нині віддаю на страту, на розп''яття тебе, сину...
А ти в покорі ідеш на муки - і зближається година...

Зболене моє серце страждає дивитись на твої муки
Увінчаного у терновім вінку, до хреста прибиті руки...
О, мій Боже милий, змилуйся над зраненим сином!..
Дай перенести біль страждання у важку хвилину...

Між двома розбійниками на хресті розп''ятий...
Затьмарився білий день, затряслась земля мати...
Віддаю тебе, мій  сину, Небесному Отцю навіки!..
Помилуй, лукавий світ... Подай душі духовні ліки!..');
