INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7379642','Букварик, друже наш!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Букварик, друже наш,
Ти нас дуже любив.
Усім допомагав і букви нас учив.
Читали по складах
Нелегко було нам.
Букварик, друже наш,
Любив наш перший клас!

Приспів:
А тепер ми молодці,
Всі читаємо книжки,
Та бабусям перед сном
Почитаємо казки!

Букварик, друже наш,
За нами не сумуй!
Ми любимо тебе -
Завжди це пам''ятай!
Прийдуть ще малюки,
Навчати будеш ти,
А ми у другий клас
Ідемо залюбки!

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7379642'), datetime('now')),datetime('now'));
