INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7381363','Не спіши, моє дитинство!..','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Тихими стежками,
Горами й долами
Йшло моє дитинство
Далі все від мами...
Зіркою котилось,
Річкою сріблилось,
Там моє дитинство
З юністю зустрілось...

Приспів:
Не спіши, моє дитинство,
Білим птахом відлітать,
Ще дозволь мені, дитинство,
На гостину завітать!..
Не спіши, моє дитинство,
В неосяжну далину,
Залиши мені, дитинство,
Травневою весну!..

Сонцем зігрівало,
На сопілці грало,
Там мене дитинство
Щастям напувало!..
Материнська пісня,
З ясена колиска -
То мого дитинства
Зоряне намисто...

Приспів.','[''pisni.org.ua'', ''cat:nostalgia'', ''Пісні з ностальгічними мотивами'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7381363'), datetime('now')),datetime('now'));
