INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7369446','Лариска','Музика: Назар Савко Слова: Назар Савко. Виконує: Назар Савко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Жила собі Лариска -
Хитренькая лиска.
Цілий день гуляла,
Співала, танцювала.
З вовчиком-братиком
За столом сиділа,
Всі сосиски з''їла.

Приспів:
Лариска, Лариска,
А де моя сосиска?
Чому порожня миска?
Ану кажи, Лариска!
Лариска, Лариска,
А де моя сосиска?
Чому порожня миска?
Куди втікаєш, лиска?

Жила собі Лариска -
Хитренькая лиска.
Цілий день гуляла,
Співала, танцювала.
З ведмедиком-мемедиком
За столом сиділа,
Всі сосиски з''їла.

Приспів.

Жила собі Лариска -
Хитренькая лиска.
Цілий день гуляла,
Співала, танцювала.
З зайчиком-стрибайчиком
За столом сиділа,
Всі сосиски з''їла.

Приспів.

Нарешті Лариска
Вину зрозуміла
І звіряток тих
На обід запросила.
Для гостей всіх мастей
Столика накрила -
І сама все з''їла!..
Ну, Лариска!
Ох, Лариска!
Ой, Лариска!
А, де Лариска?
Ой, де сосиски?

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:zhartivlyvi'', ''Дитячі пісні'', ''Жартівливі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7369446'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7369446','Лариска','Жила собі Лариска -
Хитренькая лиска.
Цілий день гуляла,
Співала, танцювала.
З вовчиком-братиком
За столом сиділа,
Всі сосиски з''їла.

Приспів:
Лариска, Лариска,
А де моя сосиска?
Чому порожня миска?
Ану кажи, Лариска!
Лариска, Лариска,
А де моя сосиска?
Чому порожня миска?
Куди втікаєш, лиска?

Жила собі Лариска -
Хитренькая лиска.
Цілий день гуляла,
Співала, танцювала.
З ведмедиком-мемедиком
За столом сиділа,
Всі сосиски з''їла.

Приспів.

Жила собі Лариска -
Хитренькая лиска.
Цілий день гуляла,
Співала, танцювала.
З зайчиком-стрибайчиком
За столом сиділа,
Всі сосиски з''їла.

Приспів.

Нарешті Лариска
Вину зрозуміла
І звіряток тих
На обід запросила.
Для гостей всіх мастей
Столика накрила -
І сама все з''їла!..
Ну, Лариска!
Ох, Лариска!
Ой, Лариска!
А, де Лариска?
Ой, де сосиски?

Приспів.');
