INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_737565','На Городі Корито Корито','Українська народна пісня. Виконує: Ніна Матвієнко, Тріо "Золоті Ключі"','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаїлки-Великдень: Українське свято Відродження Світа. Стала ж Вона сяяти. Стала Пані просити-просити. Якби Човен та Весельце рятувала б моє Серце. Повне Води налито-налито. Листки з приводу цієї Пісні: Вербний Тиждень і Шутка. Про Українські назви місяців Марець і Май. Стежки до листків про Українські традиції.','На Городі Корито-корито
Повне Води налито-налито

Там Дівчата ходили-ходили
Білоноги помили-помили

Вийшла Пані на Наш Двір на Наш Двір
На ній Сукня в Вісім Піл в Вісім Піл

Стала Жара жарити-жарити
Стала Сукня горіти-горіти

Стала Пані просити-просити
Йдіть Дівчата гасити-гасити

Йдіть Дівчата гасити-гасити
Відром Воду носити-носити

Скільки в Відрі Води є Води є
Стільки в Дівчат Правди-правди','[''pisni.org.ua'', ''cat:vesnyanky-hayivky'', ''Веснянки та гаївки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_737565'), datetime('now')),datetime('now'));
