INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7371464','Обжинки','Слова: Андрій Василенко','uk','ukraine_before_1917',NULL,NULL,'авторське подання',NULL,'При світлі сонячного дня
Хлібами зріє поле.
Землі залишиться стерня,
Зерно везуть в комори.

Приспів:
Застеляйте рушники,
Ложіть паляниці.
В нас сьогодні обжинки -
Гріх не веселиться!

України щедрий лан -
Що той ріг достатку.
Збіжжям вишитий жупан,
Ще й гопак вприсядку.

Приспів.

Відпочиньте, трударі,
Працьовиті люди,
Уклонімося землі -
Щедро родить буде!

Приспів.','[''pisni.org.ua'', ''cat:obzhynkovi'', ''Обжинкові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7371464'), datetime('now')),datetime('now'));
