INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7381446','Замело снігами','Українська народна пісня. Виконує: Оксана Сливка','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Замело снігами у Карпатах плай,
Долами й горами ходить Миколай!
Двигає пакунки в сніговій імлі,
Дідових дарунків діти ждуть малі!
Двигає пакунки в сніговій імлі,
Дідових дарунків діти ждуть малі!

Сніг паде лапатий, віхола гуде,
Тільки б не проспати, як дідусь прийде!
Насторожать вушка і заснуть... - Іде!..
Тихо під подушки дарунки кладе!
Насторожать вушка і заснуть... - Іде!..
Тихо під подушки дарунки кладе!

А вдосвіта-зрання радощі і сміх -
Здійснились бажання малюків усіх!
Лиш одна загадка цікава до сліз:
Як дідусь так гладко крізь замок проліз?..
Лиш одна загадка цікава до сліз:
Як дідусь так гладко крізь замок проліз?..','[''pisni.org.ua'', ''cat:svyatyy-mykolay'', ''Пісні про Святого Миколая'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7381446'), datetime('now')),datetime('now'));
