INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7380767','Пусти мене, моя мати','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Пусти мене, моя мати,
Та й на вечорнички,
То там хлопці чорноброві
Плетуть рукавички.

Закувала зозулина,
Сіла на лозину,
Ей, люблю, мамко, літо,
Ще ма люблю зиму.

Бо уліті на роботі
Сонечко пече мя,
А узимі, люба мамко,
Ледве жду вечера!','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7380767'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7380767','Пусти мене, моя мати','Пусти мене, моя мати,
