INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7382642','Ой, любив я дівчиноньку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, любив я дівчиноньку,
А дівчина - мене,
Не хотіли старі дати
Дівчину за мене.

Старий хотів, старий хотів,
Стара не хотіла,
Лиш сиділа на запічку
Та все воркотіла.

Воркотіла, воркотіла,
А далі — у сварку,
Старий стару макогоном,
А стара — під лавку.

Старий стару макогоном,
Стара полетіла,
Бідна ж моя головочко,
Де ся стара діла?

Чи я тобі, моя мати,
Була надоїла,
Що мене там віддала,
Де я не хотіла?

Чим я тобі, моя мати,
Була не вгодила,
Що ти мені у Богойка
Долі не просила?

Просила-м ти, моя доню,
Просила, просила,
Але твоя, моя доню,
Доля нещаслива...','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7382642'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7382642','Ой, любив я дівчиноньку','Ой, любив я дівчиноньку,
А дівчина - мене,
