INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_738767','А де Наше Купайло стояло','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Пара - любощі: Мати. Кінь - Нові Ворота. Вмивання. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Ой приїхав під Нові Ворота. Ой не вийшла Дівчина лиш Мати. Чого Вона на Купайла не вийшла. Під Калиною Дівчина там Косу Русу чесала. На Розсвіті личенько вмивала. По Півночі Черевички взувала. А де Наше Купайло стояло Ой там у Лісі Калина Були Світилки Яснії Зірки. Не гинь Миленький дам Ти Радоньку. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Да чому ти Дівчино гуляти не йдеш Стежки до листків про Українські традиції.','А де Наше Купайло стояло
То там Місяць і Сонейко сіяло

То там Яснеє Сонейко сіяє
Там Микола Кониченька сідлає

Там Микола Кониченька сідлає
До Дівчини поїхати думає

Ой приїхав під Нові Ворота
Вийди-вийди Дівчино Молода!

Ой не вийшла Дівчина лиш Мати
Та став Її так Микола питати

Чи є Моя Дівчина удома
Ой чи Вона Молоденька здорова

Чого Вона і горда і пишна
Чого Вона на Купайла не вийшла

Русу Косу звечора чесала
По Півночі Черевички взувала

На Розсвіті личенько вмивала
Тому на Купайлі не бувала','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_738767'), datetime('now')),datetime('now'));
