INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7382262','Ой, та тобі дарую','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, та тобі, перша дружко,
Дарую сороку,
Щобись собі пару найшла
Іще цього року.

Ой, та тобі старший дружбо,
Дарую качата,
Щоби тебе все любили
Молоді дівчата.

Ой, а тобі, друга дружко,
Пурхливі горобці,
Щоби тебе все любили
Молодийкі хлопці.

Ну, а тобі, другий дружбо,
Дарую маківки,
Щоби тебе все любили
Молодийкі дівки.','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7382262'), datetime('now')),datetime('now'));
