INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7388262','Новий рік не за горами','Музика: Микола Ведмедеря Слова: Юлія Хандожинська','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Новий рік не за горами,
Стелить стежку килимами,
Студить ріки всі, холодить,
Хороводи з вітром водить.
Новий рік ось, ось близенько,
Одягнемося гарненько,
За вікном дзінь, дзінь раз у раз,
Новий рік іде до нас!

Приспів:
Новий рік! Новий рік!
Новий, новий!
Буде кожен із нас хай здоровий!
Хай народиться посмішка щира!
Всім бажаємо щастя і миру!

Новий рік, немов дзвіночок,
Завітає в дитсадочок,
Привітати всіх малят,
Побажати гарних свят!
Новий рік ось, ось близенько,
Одягнемося гарненько,
За вікном дзінь, дзінь раз враз,
Новий рік іде до нас!

Приспів.','[''pisni.org.ua'', ''cat:new-year'', ''Пісні про Новий Рік'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7388262'), datetime('now')),datetime('now'));
