INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_738464','Спи, Ісусе, спи','Музика: о. Й. Кишакевич Слова: о. Й. Кишакевич. Виконує: Алексис Кохан-Будик, Оксана Роспоп, Ольга Роспоп','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Спи, Ісусе, спи,
Спатоньки ходи
Я Тебе му колисати.
Пісеньками присипляти:
"Люлі, серденько, люлі!"

Спи Лелійко, спи,
Голівку склони,
Тут,  на рученьки Марії,
Бач, вона Тебе леліє:
"Люлі, серденько, люлі!"

Спи Убогий, спи,
Рученьки склади,
Йосифа ще не видати,
Несе хлібця Тобі дати.
"Люлі, серденько, люлі!"

Спи, Терпіннє спи,
Очка зажмури.
Не питай, що колись буде,
Що зготовлять Ти хрест люди.
"Люлі, серденько, люлі!"

Спи, Ісусе, спи,
Серце відчини,
Хай при Ньому спочиваю
Тут на землі і там в Раю,
"Люлі, серденько, люлі!"','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:christian'', ''cat:dytyachi'', ''cat:kolyadky'', ''cat:kolyskovi'', ''Церковні пісні'', ''Пісні на християнську тематику'', ''Дитячі пісні'', ''Колядки'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_738464'), datetime('now')),datetime('now'));
