INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7382343','Дай ми, дівко, горівочки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Дай ми, дівко, горівочки
Напитися з склянки,
Ми привели тобі хлопця,
Що їх штири в мамки.

Дай, дівчино, горівочки,
Дай нам цілу бочку,
Ми привели тобі хлопця
В зеленім віночку.

Ой, дівчино молоденька,
Бери нас до хати,
Ми з дороги далекої,
Не годні стояти.

Ми з дороги далекої,
Топтали болото,
Та принесли тобі вінок
Дорожчий за злото.','[''pisni.org.ua'', ''cat:kolomyyky'', ''Коломийки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7382343'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7382343','Дай ми, дівко, горівочки','Дай ми, дівко, горівочки
Напитися з склянки,
