INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7392240','Школа','Музика: Володимир Будейчук Слова: Ірина Зінковська','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконують Double Shock та Сестри Басараби.','Ми були тільки вчора малими,
Світ здавався великим всім нам...
Швидко виросли і стали крутими,
Ми зірвали, ми зірвали Інстаграм!

Приспів:
Школа - відповіді, запитання!
Школа - перше у житті кохання!
Школа рідна, дякую за все!
Школа, школа, з тобою серце моє!

Нас цікавлять тільки модні тренди,
В фешн-гаджетах весь інтерес,
Лайки, рейтинг, паблік та івенти,
Лиш навчання спричиняє стрес...

Приспів. (2)

Речитатив:
Ей-ей-ей!
Вже, може, досить вчитись?
Ей-ей-ей!
І час повеселитись?
Та ти і я ми добре знаєм:
Знаннями двері відкриваєм!
Щоб стати кимось в цьому світі,
Потрібна нам шкільна освіта!

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7392240'), datetime('now')),datetime('now'));
