INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7395161','Усмішка матусі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Мама усміхається - щастя входить в дім,
Сонце оселяється назавжди у нім!
Усмішка привітна обійме мене,
І в очах розквітне диво неземне.

Приспів:
Усмішка матусі - світлий обрій мій,
Усмішка матусі - берегиня мрій!
Усмішка матусі - весен білий цвіт,
Усмішка матусі зігріває світ!

З неї починається у дитинство шлях,
Мама усміхається - райдуга в очах!
Смутку хай не знає серденько її,
Вдячно заспіваю їй свої пісні!

Приспів.','[''pisni.org.ua'', ''cat:pro-batkiv'', ''Пісні про любов до батьків'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7395161'), datetime('now')),datetime('now'));
