INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7380464','Ой, спи, дитя, колишу тя','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','*вержу - кину, **лавиця - лавка.','Ой, спи, дитя, колишу тя,
Доки не вснеш, не лишу тя.
Прикладу тя камінцями,
Сама піду за вівцями...

Вівці будуть травку пасти,
А я буду кужіль прясти...
Кужіль вержу*, пуд лавицю**...
Сама піду й на вулицю...

Хай у тебе, рибко біла,
Та й головка не хоріла...
Би дитина й одужала,
Би й ся сама колисала...

Повішу я колисочку
На зелену галузочку,
Вітер буде повівати,
Тебе, дитя, колисати...','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7380464'), datetime('now')),datetime('now'));
