INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7389240','Королева','Музика: Арсен Мірзоян Слова: Арсен Мірзоян. Виконує: Арсен Мірзоян','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Чорним чи білим за кожну клітину
Є два, є чотири, почнеш з нуля,
Пів царства за коня у тебе в полоні,
Слони на кордоні - тремтить земля.
Віддав всі клітини, цугцванг це єдине
Потрапив куди з початку гри.
Тебе не втримати, це ж твій ультиматум,
Ти любиш свій колір, як не крути!

Приспів:
І твоє декольте, і підбори -
І всі розуміють: король десь поряд!
Біле й сухе, й лід,
Ферзь розпочне гамбіт,
Нехай всі говорять!
В її обіймах скінчиться гра,
Цілуй мене - я програв!..

І все, що буде, сховає майбутнє,
Тримай за зубами язик,
Мріями не зникли, а я ще не звикнув
До того, до чого звик.
І з самого ранку сіль сиплять на рану
На перших сторінках ЗМІ.
Моя королева п''є віскі на нервах
І залишається в грі!

Приспів.','[''pisni.org.ua'', ''cat:philosophic'', ''Філософські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7389240'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_7389240','Королева','Чорним чи білим за кожну клітину
