INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_738848','Ой у Садочку обметяно','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Сад-Калина. Торг-Дари. Вибір Пари. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Свої Дівчині Даром дає. Були Світилки Яснії Зірки. Щоб ми по Петрі в Парі стали. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Ой у Садочку обметяно
Ще й Калиною обтикано

Ще й Калиною обтикано
Туди Дівчину закликано

Ой там Хлопчина з Торгом стоїть
Ой з яким Торгом з Каблучками

Ой з яким Торгом з Каблучками
Біжать Дівчата з Онучками

Чужим Дівчатам розпродує
Свої Дівчині Даром дає

А тії Дари не даремні
Щоб тії Дари не пропали

Щоб тії Дари не пропали
Щоб ми по Петрі в Парі стали

Як не по Петрі то в Осені
Щоб нам Червонців позносили','[''pisni.org.ua'', ''cat:kupalski'', ''Купальські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_738848'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_738848','Ой у Садочку обметяно','Ой у Садочку обметяно
Ще й Калиною обтикано

Ще й Калиною обтикано
Туди Дівчину закликано

Ой там Хлопчина з Торгом стоїть
Ой з яким Торгом з Каблучками

Ой з яким Торгом з Каблучками
