INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7397343','А ми повернемось!..','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'https://youtu.be/0SYFsAqOYwk','https://youtu.be/0SYFsAqOYwk Пісню виконує Валентина Лоюк.','Ще вчора ми були маленькі
І вчителька вела нас в перший клас,
Ми пізнавали світ цікавий,
І стала вона мамою для нас!..
Учила нас добро розпізнавати,
Вела за руку впевнено в життя,
А ми скоріш хотіли виростати,
Щоб полетіть з пташиного гнізда!..

Приспів:
А ми повернемось у наших дітях   |
І знову станемо на цей поріг,    |
І будем плакать, і будем радіти, |
І разом вклонимось до ваших ніг! | (2)

Повиростали ластів''ята
І хочуть вдалечінь злетіть крильми,
Та сумно рідну школу залишати -
Веселі й безтурботнії роки!..
Ще вчора ми були такі маленькі
І вчителька вела нас в перший клас,
Ми пізнавали з нею світ цікавий,
І стала вона мамою для нас!..

Приспів.','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7397343'), datetime('now')),datetime('now'));
