INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_738240','Ой мала я у коморі сало','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'З пам''яті.','*У приспіві після кожної в''язки заміняються відповідні слова з цієї в''язки. Є різні варіанти виконання приспіву, зокрема третій і шостий рядки співають ідентично одному з них.','Ой мала я у коморі сало,
Сало я носила до Сави.

Приспів:*
Ти пив, і я пила,
Ти казав - я носила
Сало до корчми до Сави,
Ти пив і я пила,
Ти казав - я носила
Сало до Сави носила.

Ой мала я у коморі яйця,
Яйця я носила до Хайці.

Приспів.

Ой мала я у коморі кури,
Кури я носила до Сури.

Приспів.

Ой мала я у коморі моркву,
Моркву я носила до Мордка.

Приспів.

Ой мала я у коморі гречку,
Гречку я носила до Гершка.

Приспів.

Ой мала я у коморі жито,
Жито я носила до жида.

Приспів.

Ой мала я у коморі просо,
Просо я носила до Рози.

Приспів.

Ой мала я у коморі гроші,
Гроші я носила до Мойші.

Приспів.

Ой мала я у коморі сало,
Сало я носила до Сари.
Ти пив, і я пила,        |
Ти казав - я носила -    |(2)
Сала в коморі не стало!  |    Голос 1','[''pisni.org.ua'', ''cat:halycki'', ''Пісні з Галичини'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_738240'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_738240','Ой мала я у коморі сало','Ой мала я у коморі сало,
