INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_739745','Тріє царі','Музика: о. В.Стех Слова: о. В.Стех','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Тріє царі, де йдете?
Глядати Дитятка
Царя Спаса всього світу,
Божого Ягнятка.

Воно в шопі ні престола,
Ні скиптра немає,
А вже в світі Його слава
Вам Його звіщає.

Хоч у Бога народився,
Нікому не знаним,
А вже з неба вість несеться,
Що Він буде славним:

Тая зоря пре чудесна
Різдво нам голосить
І з поклоном вас до Нього
І з востока просить.

Поспішіть же тріє царі,
В вертеп за звіз дою;
Там знайдете Бога Сина,
Що став всіх слугою!

Поспішіть же до Дитятка
Та дайте Му дари,
А від нас поклін низенький
Зложіть Му звіздарі!

А з поклоном ще вас просим
Зложіть Му в офіру
Наші серця, в любов повні,
Багаті на віру.

Хай за тую малу жертву
Він нас просвіщає
Тут, на землі і там, в небі,
Де престол Свій має.    З голосу сім''ї о.Горошка, с.Яблониця','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:kolyadky'', ''Церковні пісні'', ''Колядки'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_739745'), datetime('now')),datetime('now'));
