INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_7398161','Люде, мій люде',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Люде, мій люде, що тобі вчинив Я,
Чим засмутив тебе, чим тобі завинив?
Вивів тебе Я із-під фараона,
А ти поклав хрест на мої рамена.
Приспів.
Привів тебе Я в край хлібів і меду,
А ти зготовив смерть Мені ганебну.
Приспів.
Ніжно плекав вас, грона винограду,
Ви ж напоїли гірким оцтом зради.
Приспів.
Послав за тебе Єгипту покарання,
Ти ж мене видав на тяжкі страждання.
Приспів.','[''pisni.org.ua'', ''cat:strasni'', ''Страсні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_7398161'), datetime('now')),datetime('now'));
